import React from "react"
import AddUser from "./AddUser"
import { IoCloseCircleSharp, IoHammerSharp } from 'react-icons/io5'

class User extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            editForm: false
        }
    }

    render() {
        const { user, onDelete, onEdit } = this.props;  

        return (
            <div className="user">
                <IoCloseCircleSharp 
                    onClick={() => onDelete(user.id)} 
                    className="delete-icon" 
                />
                <IoHammerSharp 
                    onClick={() => {
                        this.setState({ 
                            editForm: !this.state.editForm  // ← ИСПРАВЛЕНО!
                        })
                    }} 
                    className="edit-icon" 
                />
                <h3>{user.firstname} {user.lastname}</h3>
                <p>{user.bio}</p>
                <b>{user.isHappy ? 'Хапи' : 'Бедни'}</b>

                {this.state.editForm && (
                    <AddUser 
                        user={user}  // ← передаем данные пользователя
                        onAdd={onEdit} 
                    />
                )}
            </div>
        )
    }
}

export default User
